<?php require_once 'db.php'; verify_csrf(); if($_SERVER['REQUEST_METHOD']==='POST'){ $email=filter_var($_POST['email']??'',FILTER_VALIDATE_EMAIL); $pass=$_POST['password']??''; $s=pdo()->prepare('SELECT u.*,r.name role FROM users u JOIN roles r ON r.id=u.role_id WHERE u.email=? AND u.status="active"'); $s->execute([$email]); $u=$s->fetch(); if($u&&password_verify($pass,$u['password'])){ session_regenerate_id(true); $_SESSION['user']=['id'=>$u['id'],'name'=>$u['name'],'email'=>$u['email'],'role'=>$u['role']]; log_activity($u['id'],'Logged in'); redirect_by_role($u['role']); } flash('Invalid login credentials.','err'); } app_header('Login'); ?><form class="auth card" method="post"><h1>Login</h1><?=csrf_field()?><input name="email" type="email" placeholder="Email" required><input name="password" type="password" placeholder="Password" required><button class="btn">Login</button><p><a href="forgot_password.php">Forgot password?</a> • <a href="register.php">Create student account</a></p></form><?php app_footer(); ?>
